// src/pages/MarketingHome.js
import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Award, Clock, Shield, Check } from 'lucide-react';
import Navbar from '../components/layout/Navbar'; // Make sure this path is correct
import Footer from '../components/layout/Footer'; // Make sure this path is correct

const MarketingHome = () => {
  const [email, setEmail] = useState('');
  const navigate = useNavigate();
  
  useEffect(() => {
    // Debug log to check if component is mounting
    console.log('MarketingHome component mounted');
    
    // Explicitly show what icon components are available
    console.log('Icons available:', { Award, Clock, Shield, Check });
  }, []);
  
  const handleSignup = (e) => {
    e.preventDefault();
    localStorage.setItem('signupEmail', email);
    navigate('/register');
  };

  // Test content to verify rendering
  const TestContent = () => (
    <div className="p-8 m-8 bg-red-100 text-center rounded">
      <h2 className="text-xl font-bold">TEST CONTENT</h2>
      <p>If you can see this, content rendering works!</p>
    </div>
  );

  return (
    <div className="bg-gray-50 min-h-screen">
      {/* Navbar - this is visible */}
      <Navbar />
      
      {/* Debug component to test rendering */}
      <TestContent />
      
      {/* Content with margin-top to clear fixed navbar */}
      <div className="mt-20 px-4">
        {/* Test hero section with simpler styling */}
        <section className="bg-blue-500 text-white p-8 rounded-lg mb-8">
          <h1 className="text-3xl font-bold mb-4">Supporting Fitness For Healthy Aging</h1>
          <p className="mb-4">Simplified hero section for testing</p>
          
          <form onSubmit={handleSignup} className="flex flex-col sm:flex-row gap-3">
            <input
              type="email"
              placeholder="Enter your email"
              className="px-4 py-2 rounded text-black"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <button 
              type="submit"
              className="bg-white text-blue-600 px-4 py-2 rounded"
            >
              Start Free
            </button>
          </form>
        </section>
        
        {/* Simplified features section */}
        <section className="mb-8">
          <h2 className="text-2xl font-bold text-center mb-4">Key Features</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white p-4 rounded shadow">Feature 1</div>
            <div className="bg-white p-4 rounded shadow">Feature 2</div>
            <div className="bg-white p-4 rounded shadow">Feature 3</div>
          </div>
        </section>
      </div>
      
      {/* Footer - this is visible */}
      <Footer />
    </div>
  );
};

export default MarketingHome;
